import React, { useState, useEffect } from 'react';
import fishData from './FishData.json';

export default function KnowledgePage() {
    const [fishes, setFishes] = useState([]);
    const [expandedFishIds, setExpandedFishIds] = useState([]);

    useEffect(() => {
        setFishes(fishData.freshwater_fish_vietnam);
    }, []);

    const toggleFishInfo = (id) => {
        setExpandedFishIds((prev) =>
            prev.includes(id) ? prev.filter((fid) => fid !== id) : [...prev, id]
        );
    };

    return (
        <div className="main-content p-6 bg-gray-100 min-h-screen">
            <h1 className="text-3xl font-bold text-center mb-8 text-blue-800">
                Kiến thức về các loài cá nước ngọt Việt Nam
            </h1>
            <div className="grid grid-cols-1 sm:grid-cols-2 md:grid-cols-2 lg:grid-cols-4 gap-6">
                {fishes.map((fish) => {
                    const isExpanded = expandedFishIds.includes(fish.id);
                    return (
                        <div
                            key={fish.id}
                            className="bg-white rounded-lg shadow-md p-4 flex flex-col justify-between"
                        >
                            {!isExpanded ? (
                                <>
                                    <img
                                        src={fish.image_url}
                                        alt={fish.name}
                                        className="w-full h-48 object-cover rounded"
                                        onError={(e) => {
                                            e.target.onerror = null;
                                            e.target.src = '/images/not-found.jpg';
                                        }}
                                    />
                                    <h2 className="text-xl font-semibold text-blue-600 text-center mt-2">
                                        {fish.name}
                                    </h2>
                                </>
                            ) : (
                                <div className="text-sm text-gray-700 space-y-1">
                                    <p>
                                        <span className="font-medium">Đặc điểm:</span>{' '}
                                        {fish.characteristics.appearance}
                                    </p>
                                    <p>
                                        <span className="font-medium">Kích cỡ:</span>{' '}
                                        {fish.characteristics.size}
                                    </p>
                                    <p>
                                        <span className="font-medium">Tập tính:</span> {fish.behavior}
                                    </p>
                                    <p>
                                        <span className="font-medium">Mồi yêu thích:</span>{' '}
                                        {fish.favorite_bait}
                                    </p>
                                    <p>
                                        <span className="font-medium">Thông tin:</span> {fish.info}
                                    </p>
                                </div>
                            )}
                            <button
                                onClick={() => toggleFishInfo(fish.id)}
                                className="mt-4 px-4 py-2 bg-blue-500 text-white rounded hover:bg-blue-600 transition"
                            >
                                Infor
                            </button>
                        </div>
                    );
                })}
            </div>
        </div>
    );
}
